# Dependency graph for AI roadmap sequencing
# Topological sort to find valid build order

from collections import deque

def topological_sort(use_cases: dict) -> list:
    in_degree = {uc: 0 for uc in use_cases}
    for uc, deps in use_cases.items():
        for dep in deps:
            in_degree[uc] += 1

    queue = deque([uc for uc, deg in in_degree.items() if deg == 0])
    order = []

    while queue:
        current = queue.popleft()
        order.append(current)
        for uc, deps in use_cases.items():
            if current in deps:
                in_degree[uc] -= 1
                if in_degree[uc] == 0:
                    queue.append(uc)

    if len(order) != len(use_cases):
        raise ValueError("Circular dependency detected in roadmap")
    return order

# Dependency map: key = use case, value = list of prerequisites
roadmap = {
    "llm_gateway":           [],
    "data_governance":       [],
    "pilot_use_case":        ["llm_gateway", "data_governance"],
    "mlops_platform":        ["llm_gateway"],
    "domain_teams":          ["pilot_use_case", "mlops_platform"],
    "observability":         ["mlops_platform"],
    "agentic_workflows":     ["domain_teams", "observability"],
    "self_service_ai":       ["mlops_platform", "domain_teams"],
    "ai_native_products":    ["agentic_workflows", "self_service_ai"],
}

build_order = topological_sort(roadmap)
print("Valid build sequence:")
for i, uc in enumerate(build_order, 1):
    deps = roadmap[uc]
    print(f"  {i:2d}. {uc:<25} depends on: {deps if deps else 'none'}")

# Horizon assignment: classify use cases by capability readiness
# Use cases are assigned to horizons based on their dependency depth

def assign_horizon(use_cases: dict) -> dict:
    horizon_map = {}
    resolved = set()
    iteration = 0
    max_iterations = len(use_cases) + 1

    while len(resolved) < len(use_cases) and iteration < max_iterations:
        for uc, deps in use_cases.items():
            if uc in resolved:
                continue
            if all(d in resolved for d in deps):
                depth = max((horizon_map.get(d, 0) for d in deps), default=0)
                if depth == 0 and not deps:
                    horizon_map[uc] = 1
                elif depth <= 1:
                    horizon_map[uc] = 1 if not deps else 2
                else:
                    horizon_map[uc] = depth + 1
                resolved.add(uc)
        iteration += 1

    return horizon_map

horizons = assign_horizon(roadmap)
for horizon_num in [1, 2, 3]:
    items = [uc for uc, h in horizons.items() if h == horizon_num]
    print(f"Horizon {horizon_num}: {items}")

# Dependency health check: detect stale or violated dependencies
# Run before each phase gate review

from datetime import date

def check_dependency_violations(nodes: dict, completion_dates: dict, today: date = None) -> list:
    if today is None:
        today = date.today()
    violations = []
    for node, deps in nodes.items():
        node_start = completion_dates.get(node, {}).get("planned_start")
        for dep in deps:
            dep_completion = completion_dates.get(dep, {}).get("actual_completion")
            if node_start and dep_completion is None:
                dep_planned = completion_dates.get(dep, {}).get("planned_completion")
                if dep_planned and node_start <= dep_planned:
                    violations.append({
                        "type": "SEQUENCING_RISK",
                        "node": node,
                        "blocked_by": dep,
                        "message": f"{node} planned to start {node_start} but {dep} not complete until {dep_planned}"
                    })
    return violations

# Example: dependency status as of Phase 1 gate review
nodes = {
    "mlops_platform": ["llm_gateway"],
    "domain_teams": ["pilot_use_case", "mlops_platform"],
    "agentic_workflows": ["domain_teams", "observability"],
}
completion_dates = {
    "llm_gateway":    {"actual_completion": date(2025, 3, 15)},
    "pilot_use_case": {"actual_completion": date(2025, 4, 1)},
    "mlops_platform": {"planned_start": date(2025, 4, 1), "actual_completion": None, "planned_completion": date(2025, 6, 30)},
    "observability":  {"planned_completion": date(2025, 7, 15)},
    "domain_teams":   {"planned_start": date(2025, 5, 1)},   # RISK: starts before mlops done
    "agentic_workflows": {"planned_start": date(2025, 9, 1)},
}
violations = check_dependency_violations(nodes, completion_dates, today=date(2025, 4, 15))
for v in violations:
    print(f"[{v['type']}] {v['message']}")
